#define HIP_CHECK(cmd)                                                          \
    do {                                                                        \
        hipError_t err = cmd;                                                   \
        if (err != hipSuccess) {                                                \
            std::cerr << "HIP error: " << #cmd << " -> "                       \
                      << hipGetErrorString(err) << " (" << err << ")"         \
                      << " at " << __FILE__ << ":" << __LINE__ << "\n";       \
            std::exit(EXIT_FAILURE);                                            \
        }                                                                       \
    } while (0)

__global__ void hbm_read_kernel(const float4* __restrict__ data,
                                size_t n,
                                float* __restrict__ sink,
                                unsigned long long* __restrict__ timer,
                                unsigned long long* __restrict__ start_counter,
                                unsigned long long* __restrict__ end_counter) {
    const size_t tid    = blockIdx.x * blockDim.x + threadIdx.x;
    const size_t stride = blockDim.x * gridDim.x;

    if (threadIdx.x == 0) {
        unsigned long long prev = atomicAdd(start_counter, 1ULL);
        if (prev == 0ULL) {
            *timer = __builtin_amdgcn_s_memrealtime();
        }
    }
    __syncthreads();

    float sum_x = 0.0f, sum_y = 0.0f, sum_z = 0.0f, sum_w = 0.0f;
    for (size_t i = tid; i < n; i += stride) {
        const float4 v = data[i];
        sum_x += v.x;
        sum_y += v.y;
        sum_z += v.z;
        sum_w += v.w;
    }

    __shared__ float s[256];
    s[threadIdx.x] = sum_x + sum_y + sum_z + sum_w;
    __syncthreads();
#pragma unroll
    for (int offset = blockDim.x / 2; offset > 0; offset >>= 1) {
        if (threadIdx.x < offset) s[threadIdx.x] += s[threadIdx.x + offset];
        __syncthreads();
    }
    if (threadIdx.x == 0) {
        sink[blockIdx.x] = s[0];
        unsigned long long prev = atomicAdd(end_counter, 1ULL);
        if (prev == (gridDim.x - 1)) {
            timer[1] = __builtin_amdgcn_s_memrealtime();
        }
    }
}

int main() {
    HIP_CHECK(hipSetDevice(0));
    hipDeviceProp_t prop;
    HIP_CHECK(hipGetDeviceProperties(&prop, 0));
    std::cerr << "clockRate kHz=" << prop.clockRate << "\n";

    constexpr size_t GB = 1024ULL * 1024ULL * 1024ULL;
    const size_t buffer_bytes = 3ULL * GB;
    const size_t n = buffer_bytes / sizeof(float4);
    const int blockSize = 256;
    const int numBlocks = 16384;
    const int timedIters = 64;

    void* d_data; HIP_CHECK(hipMalloc(&d_data, buffer_bytes));
    void* d_sink; HIP_CHECK(hipMalloc(&d_sink, numBlocks * sizeof(float)));
    HIP_CHECK(hipMemset(d_data, 1, buffer_bytes));

    unsigned long long* d_timer;
    unsigned long long* d_start_counter;
    unsigned long long* d_end_counter;
    HIP_CHECK(hipMalloc(&d_timer, 2 * sizeof(unsigned long long)));
    HIP_CHECK(hipMalloc(&d_start_counter, sizeof(unsigned long long)));
    HIP_CHECK(hipMalloc(&d_end_counter, sizeof(unsigned long long)));

    // warmup
    for (int i = 0; i < 5; ++i) {
        HIP_CHECK(hipMemset(d_start_counter, 0, sizeof(unsigned long long)));
        HIP_CHECK(hipMemset(d_end_counter, 0, sizeof(unsigned long long)));
        hbm_read_kernel<<<numBlocks, blockSize>>>(
            static_cast<const float4*>(d_data), n,
            static_cast<float*>(d_sink), d_timer, d_start_counter, d_end_counter);
    }
    HIP_CHECK(hipDeviceSynchronize());

    std::vector<double> times(timedIters);
    hipEvent_t loop_start, loop_stop;
    HIP_CHECK(hipEventCreate(&loop_start));
    HIP_CHECK(hipEventCreate(&loop_stop));
    HIP_CHECK(hipEventRecord(loop_start, 0));
    for (int i = 0; i < timedIters; ++i) {
        HIP_CHECK(hipMemset(d_start_counter, 0, sizeof(unsigned long long)));
        HIP_CHECK(hipMemset(d_end_counter, 0, sizeof(unsigned long long)));
        hbm_read_kernel<<<numBlocks, blockSize>>>(
            static_cast<const float4*>(d_data), n,
            static_cast<float*>(d_sink), d_timer, d_start_counter, d_end_counter);
    }
    HIP_CHECK(hipEventRecord(loop_stop, 0));
    HIP_CHECK(hipDeviceSynchronize());

    unsigned long long timer[2];
    HIP_CHECK(hipMemcpy(timer, d_timer, sizeof(timer), hipMemcpyDeviceToHost));
    double internal_ms = static_cast<double>(timer[1] - timer[0]) / prop.clockRate;

    float loop_ms = 0;
    HIP_CHECK(hipEventElapsedTime(&loop_ms, loop_start, loop_stop));
    double loop_per_iter_ms = loop_ms / timedIters;

    std::cerr << std::fixed << std::setprecision(4)
              << "internal last iter ms=" << internal_ms
              << " loop per-iter ms=" << loop_per_iter_ms << "\n";

    double bw_internal = static_cast<double>(buffer_bytes) / (internal_ms * 1e6);
    double bw_loop = static_cast<double>(buffer_bytes) / (loop_per_iter_ms * 1e6);

    std::cout << std::fixed << std::setprecision(2)
              << "HBM_BANDWIDTH_GBPS_INTERNAL=" << bw_internal << "\n"
              << "HBM_BANDWIDTH_GBPS_LOOP=" << bw_loop << "\n"
              << "buffer_bytes=" << buffer_bytes << "\n";

    HIP_CHECK(hipFree(d_data));
    HIP_CHECK(hipFree(d_sink));
    HIP_CHECK(hipFree(d_timer));
    HIP_CHECK(hipFree(d_start_counter));
    HIP_CHECK(hipFree(d_end_counter));
    return 0;
}
